def calculate_total_price(item_prices, tax_rate):
    subtotal = sum(item_prices)
    return subtotal * (1 + tax_rate)

def get_user_by_email(email_address, user_database):
    for user_record in user_database:
        if user_record['email'] == email_address:
            return user_record
    return None

class ShoppingCart:
    def __init__(self):
        self.items = []
    def add_item(self, product_name, quantity):
        self.items.append({'name': product_name, 'qty': quantity})

def is_palindrome(input_string):
    cleaned = input_string.lower().replace(' ', '')
    return cleaned == cleaned[::-1]

def fibonacci_sequence(length):
    sequence = [0, 1]
    for index in range(2, length):
        sequence.append(sequence[index - 1] + sequence[index - 2])
    return sequence

def merge_sorted_lists(first_list, second_list):
    merged_result = []
    i, j = 0, 0
    while i < len(first_list) and j < len(second_list):
        if first_list[i] <= second_list[j]:
            merged_result.append(first_list[i]); i += 1
        else:
            merged_result.append(second_list[j]); j += 1
    return merged_result + first_list[i:] + second_list[j:]

def count_word_occurrences(text, target_word):
    words = text.lower().split()
    return words.count(target_word.lower())

def find_maximum_value(number_list):
    if not number_list:
        return None
    return max(number_list)

def process_data(data, n):
    result = []
    for i in range(n):
        temp = data[i] * 2
        result.append(temp)
    return result

class Item:
    def __init__(self, n, p):
        self.name = n
        self.price = p
    def total(self, qty):
