def check(s):
    res = True
    for ch in s:
        if not ch.isalpha():
            res = False
    return res

def calc(lst):
    a = 0
    for x in lst:
        a = a + x*x
    return a

def sort_data(data):
    n = len(data)
    for i in range(n):
        for j in range(n-1):
            if data[j] > data[j+1]:
                data[j], data[j+1] = data[j+1], data[j]
    return data

def find(target, items):
    for idx, x in enumerate(items):
        if x == target:
            return idx
    return -1

class Node:
    def __init__(self, v):
        self.val = v
        self.next = None

def update(d, k, v):
    if k in d:
        d[k] = v
    else:
        d[k] = v
    return d

def sum_list(arr):
    total = 0
    for x in arr:
        total += x
    return total

